// Normaliza y valida cada fila del Sheet antes de enviarla a Supabase.
//   - lowercase + trim en canal y metric_type
//   - fecha a 'YYYY-MM-DD' (acepta Date de Sheets o string)
//   - inversion_plan y kpi_target a número
//   - descarta filas con campos obligatorios faltantes o valores inválidos

const CANALES = new Set([
  'google_ads', 'meta_ads', 'tiktok_ads', 'linkedin_ads', 'youtube_ads',
  'programmatic', 'tv', 'radio', 'ooh', 'print', 'influencer', 'email', 'other',
]);

const METRICAS = new Set([
  'impressions', 'clicks', 'sessions', 'conversions', 'leads',
  'sales', 'revenue', 'cpa', 'cpc', 'ctr', 'roas',
]);

const toIsoDate = (value) => {
  if (!value) return null;
  if (value instanceof Date) return value.toISOString().slice(0, 10);
  const str = String(value).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  const m = str.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (m) {
    const [, d, mo, y] = m;
    return `${y}-${mo.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }
  const parsed = new Date(str);
  if (!Number.isNaN(parsed.getTime())) return parsed.toISOString().slice(0, 10);
  return null;
};

const toNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(String(value).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
};

const output = [];
const errors = [];

for (const [i, item] of items.entries()) {
  const row = item.json;
  const fecha = toIsoDate(row.fecha);
  const canal = String(row.canal ?? '').trim().toLowerCase();
  const campania = String(row.campania ?? '').trim();
  const inversion_plan = toNumber(row.inversion_plan);
  const kpi_target = toNumber(row.kpi_target);
  const metric_type = String(row.metric_type ?? '').trim().toLowerCase();
  const notas = row.notas ? String(row.notas).trim() : null;

  const rowErrors = [];
  if (!fecha) rowErrors.push('fecha inválida');
  if (!CANALES.has(canal)) rowErrors.push(`canal inválido: "${canal}"`);
  if (!campania) rowErrors.push('campania vacía');
  if (inversion_plan === null) rowErrors.push('inversion_plan inválida');
  if (kpi_target === null) rowErrors.push('kpi_target inválido');
  if (!METRICAS.has(metric_type)) rowErrors.push(`metric_type inválido: "${metric_type}"`);

  if (rowErrors.length > 0) {
    errors.push({ fila: i + 2, errores: rowErrors, raw: row });
    continue;
  }

  output.push({
    json: { fecha, canal, campania, inversion_plan, kpi_target, metric_type, notas },
  });
}

if (errors.length > 0) {
  console.warn('Filas con errores:', JSON.stringify(errors, null, 2));
}

return output;
